#include <iostream>
#include <string>

class BankAccount {
private:
    std::string owner_name;
    double balance{0.0};

public:
    BankAccount(const std::string& owner, double initial_deposit) 
        : owner_name(owner) {
        if (initial_deposit >= 0.0) {
            balance = initial_deposit;
        }
    }

    std::string get_owner() const { return owner_name; }
    double get_balance() const { return balance; }

    void deposit(double amount) {
        if (amount > 0.0) {
            balance += amount;
        }
    }

    bool withdraw(double amount) {
        if (amount > 0.0 && balance >= amount) {
            balance -= amount;
            return true;
        }
        return false;
    }
};

int main() {
    BankAccount account("Alice", 100.0);
    account.deposit(50.0);
    if (account.withdraw(30.0)) {
        std::cout << account.get_owner() << " has a remaining balance of $" << account.get_balance() << "\n";
    }
    return 0;
}

