#include <iostream>
#include <string>
#include <memory>
#include <vector>

class IPaymentProcessor {
public:
    virtual ~IPaymentProcessor() = default;
    virtual bool process_payment(double amount) = 0;
};

class CreditCardProcessor : public IPaymentProcessor {
private:
    std::string card_number;
    std::string security_code;
public:
    CreditCardProcessor(std::string card, std::string cvv)
        : card_number(std::move(card)), security_code(std::move(cvv)) {}

    bool process_payment(double amount) override {
        std::cout << "[CreditCard] Processing payment of $" << amount 
                  << " using masked card: ****" << card_number.substr(12) << "\n";
        return true;
    }
};

class PayPalProcessor : public IPaymentProcessor {
private:
    std::string email;
public:
    explicit PayPalProcessor(std::string mail) : email(std::move(mail)) {}

    bool process_payment(double amount) override {
        std::cout << "[PayPal] Processing payment of $" << amount 
                  << " via user account: " << email << "\n";
        return true;
    }
};

class ShoppingCart {
private:
    double total_amount{0.0};
    std::unique_ptr<IPaymentProcessor> payment_gateway;
public:
    void add_item(double price) {
        total_amount += price;
    }
    void set_payment_method(std::unique_ptr<IPaymentProcessor> processor) {
        payment_gateway = std::move(processor);
    }
    void checkout() {
        if (payment_gateway && total_amount > 0.0) {
            if (payment_gateway->process_payment(total_amount)) {
                std::cout << "Checkout succeeded! Total charged: $" << total_amount << "\n";
                total_amount = 0.0;
            }
        } else {
            std::cout << "Checkout failed: No payment processor or empty cart.\n";
        }
    }
};

int main() {
    ShoppingCart cart;
    cart.add_item(49.99);
    cart.add_item(150.01);

    std::unique_ptr<IPaymentProcessor> user_card = 
        std::make_unique<CreditCardProcessor>("1234567812349999", "123");

    cart.set_payment_method(std::move(user_card));
    cart.checkout();
    return 0;
}

