class IAudioDevice {
public:
    virtual ~IAudioDevice() = default;
    virtual void play() = 0;
    virtual void stop() = 0;
};

class Headphone : public IAudioDevice {
private:
    int volume{50};
public:
    void set_volume(int vol) {
        if (vol >= 0 && vol <= 100) { volume = vol; }
    }
    void play() override {
        if (volume > 85) {
            std::cout << "Volume exceeds safety limits (85). Access denied.\n";
        } else {
            std::cout << "Playing sound at safe level " << volume << "\n";
        }
    }
    void stop() override {
        std::cout << "Audio stopped.\n";
    }
};

#include <array>
#include <stdexcept>

class Matrix2D {
private:
    std::array<std::array<int, 2>, 2> data{{{0, 0}, {0, 0}}};
public:
    void set_element(size_t row, size_t col, int val) {
        if (row >= 2 || col >= 2) {
            throw std::out_of_range("Index out of bounds");
        }
        data[row][col] = val;
    }
    int get_element(size_t row, size_t col) const {
        if (row >= 2 || col >= 2) {
            throw std::out_of_range("Index out of bounds");
        }
        return data[row][col];
    }
};

